/// Re-arms `withObservationTracking` after every change so the status item
/// keeps mirroring the store. Tracking fires exactly once per registration.
private func trackStoreChanges(store: UsageStore) {
    withObservationTracking {
        _ = store.menuBarSegments
        _ = store.menuBarText
    } onChange: { [weak self] in
        Task { @MainActor in
            guard let self, let store = self.usageStore else { return }
            self.diagOnChangeCount += 1
            let segments = store.menuBarSegments
            let text = store.menuBarText
            if segments == self.diagLastSegments && text == self.diagLastText {
                self.diagIdenticalRepublishCount += 1
            }
            self.diagLastSegments = segments
            self.diagLastText = text
            self.refreshStatusItemImage()
            self.trackStoreChanges(store: store)
        }
    }
}

// MARK: - CPU diagnostics

private func startDiagnosticsLogging() {
    guard diagStatsTask == nil else { return }
    Loggers.app.log(.info, "[CPU-DIAG] starting menu-bar refresh diagnostics (flush every 2 s)")
    diagStatsTask = Task { @MainActor [weak self] in
        while !Task.isCancelled {
            try? await Task.sleep(nanoseconds: 2 * 1_000_000_000)
            guard let self else { return }
            let refresh = self.diagRefreshCount
            let onChange = self.diagOnChangeCount
            let identical = self.diagIdenticalRepublishCount
            let appearance = self.diagAppearanceFireCount
            self.diagRefreshCount = 0
            self.diagOnChangeCount = 0
            self.diagIdenticalRepublishCount = 0
            self.diagAppearanceFireCount = 0
            let shortCircuitRefresh = self.diagShortCircuitedRefreshes
            let shortCircuitAppearance = self.diagShortCircuitedAppearance
            self.diagShortCircuitedRefreshes = 0
            self.diagShortCircuitedAppearance = 0
            Loggers.app.log(
                .info,
                "[CPU-DIAG] last 2 s — refresh=\(refresh) (skipped=\(shortCircuitRefresh)) onChange=\(onChange) identicalRepublish=\(identical) appearanceKVO=\(appearance) (skipped=\(shortCircuitAppearance))"
            )
        }
    }
}

